#include <bits/stdc++.h>
using namespace std;
const int N=55;
struct node
{
    int x,y;
} a[N];
int n,b[N][N];
int main()
{
    cin>>n;
    for(int i=1;i<=n;i++) cin>>a[i].x>>a[i].y;
    memset(b,0x3f,sizeof(b));
    for(int i=1;i<n;i++)
    {
        for(int j=i+1;j<=n;j++)
        {
            b[i][j]=b[j][i]=abs(a[i].x-a[j].x)+abs(a[i].y-a[j].y);
        }
    }
    for(int k=1;k<=n;k++)
	{
		for(int i=1;i<=n;i++)
		{
			for(int j=1;j<=n;j++) b[i][j]=min(b[i][j],max(b[i][k],b[k][j]));
		}
	}
    int ans=0;
    for(int i=1;i<n;i++)
    {
        for(int j=i+1;j<=n;j++)
        {
            ans=max(ans,b[i][j]);
        }
    }
    cout<<(ans+1)/2;
    return 0;
}
